sql:
SELECT 
    (SELECT product_name FROM products WHERE product_id = 0) as product_name, 
    (SELECT size_value FROM sizes WHERE size_id = 1) as size_value;

external_knowledge:
- 'Land of the free and the home of the brave' refers to the USA; 
- 'items' refers to the product names;
- 'sizes' refers to size identifiers;
- 'costs' refers to the prices;
- 'goods' refers to products.

